class DeepLinkHandler {
  static final DeepLinkHandler _instance = DeepLinkHandler._internal();
  factory DeepLinkHandler() => _instance;
  DeepLinkHandler._internal();

  StreamSubscription? _linkSubscription;
  BuildContext? _context;

  void initialize(BuildContext context) {
    _context = context;
    _handleInitialLink();
    _handleIncomingLinks();
  }

  Future<void> _handleInitialLink() async {
    try {
      final initialLink = await getInitialLink();
      if (initialLink != null) {
        _processLink(initialLink);
      }
    } on PlatformException catch (e) {
      print('Failed to get initial link: $e');
    }
  }

  void _handleIncomingLinks() {
    _linkSubscription = linkStream.listen((String? link) {
      if (link != null) {
        _processLink(link);
      }
    }, onError: (err) {
      print('Error handling incoming link: $err');
    });
  }

  void _processLink(String link) {
    if (_context == null) return;

    final uri = Uri.parse(link);
    
    if (uri.scheme != 'myapp') {
      print('Invalid scheme: ${uri.scheme}');
      return;
    }

    final path = uri.host;
    final pathSegments = uri.pathSegments;
    final queryParams = uri.queryParameters;

    switch (path) {
      case 'profile':
        _handleProfileDeepLink(pathSegments, queryParams);
        break;
      case 'payment':
        _handlePaymentDeepLink(pathSegments, queryParams);
        break;
      case 'product':
        _handleProductDeepLink(pathSegments, queryParams);
        break;
      case 'campaign':
        _handleCampaignDeepLink(pathSegments, queryParams);
        break;
      case 'notification':
        _handleNotificationDeepLink(pathSegments, queryParams);
        break;
      default:
        _handleUnknownDeepLink(path, pathSegments, queryParams);
    }
  }

  void _handleProfileDeepLink(List<String> segments, Map<String, String> params) {
    if (segments.isNotEmpty) {
      final userId = segments[0];
      Navigator.of(_context!).pushNamed(
        '/profile',
        arguments: ProfileArguments(
          userId: userId,
          tab: params['tab'],
          source: params['source'],
        ),
      );
    }
  }

  void _handlePaymentDeepLink(List<String> segments, Map<String, String> params) {
    if (segments.isNotEmpty) {
      final action = segments[0];
      
      if (action == 'confirm') {
        Navigator.of(_context!).pushNamed(
          '/payment/confirm',
          arguments: PaymentArguments(
            transactionId: params['transaction_id'],
            amount: params['amount'],
            status: params['status'],
            orderId: params['order_id'],
          ),
        );
      } else if (action == 'success') {
        Navigator.of(_context!).pushNamed(
          '/payment/success',
          arguments: PaymentArguments(
            transactionId: params['transaction_id'],
            orderId: params['order_id'],
          ),
        );
      } else if (action == 'failed') {
        Navigator.of(_context!).pushNamed(
          '/payment/failed',
          arguments: PaymentArguments(
            transactionId: params['transaction_id'],
            error: params['error'],
          ),
        );
      }
    }
  }

  void _handleProductDeepLink(List<String> segments, Map<String, String> params) {
    if (segments.isNotEmpty) {
      final productId = segments[0];
      Navigator.of(_context!).pushNamed(
        '/product',
        arguments: ProductArguments(
          productId: productId,
          variant: params['variant'],
          campaignId: params['campaign_id'],
          referrer: params['ref'],
        ),
      );
    }
  }

  void _handleCampaignDeepLink(List<String> segments, Map<String, String> params) {
    if (segments.isNotEmpty) {
      final campaignId = segments[0];
      Navigator.of(_context!).pushNamed(
        '/campaign',
        arguments: CampaignArguments(
          campaignId: campaignId,
          source: params['source'],
          medium: params['medium'],
          content: params['content'],
        ),
      );
    }
  }

  void _handleNotificationDeepLink(List<String> segments, Map<String, String> params) {
    final type = params['type'];
    final id = params['id'];

    switch (type) {
      case 'message':
        Navigator.of(_context!).pushNamed(
          '/messages',
          arguments: {'messageId': id},
        );
        break;
      case 'order':
        Navigator.of(_context!).pushNamed(
          '/orders',
          arguments: {'orderId': id},
        );
        break;
      case 'promotion':
        Navigator.of(_context!).pushNamed(
          '/promotions',
          arguments: {'promotionId': id},
        );
        break;
      default:
        Navigator.of(_context!).pushNamed('/notifications');
    }
  }

  void _handleUnknownDeepLink(String path, List<String> segments, Map<String, String> params) {
    print('Unknown deep link: $path');
    Navigator.of(_context!).pushNamed('/');
  }

  void dispose() {
    _linkSubscription?.cancel();
    _context = null;
  }
}

